		RegisterClassVariableComment("LBGroupSettingsConfig", "inviteActionEnabled", "When enabled, players can only use the ingame action to invite people and cannot see the list of players to invite them on the map menu. If you don't see the list of online players on the Group manage page, but you want to have it, disable this option");
		RegisterClassVariableComment("LBGroupSettingsConfig", "inviteActionShowName", "Show the name of the player you invite in the action text");
		RegisterClassVariableComment("LBGroupSettingsConfig", "preventFriendlyFire", "Set to 1 to disable players taking damage from players, which are in the same group as them. That only prevents the player from dying from direct hits like bullets fired by the other player or melee hits. Things like clothing will still be damaged");
		RegisterClassVariableComment("LBGroupSettingsConfig", "preventFriendlyFireOnlyInSameSubgroup", "Set to 1 to only prevent friendly fire when they are in the same subgroup (`enableSubGroups` must be enabled for that). Otherwise players will still take damage even though they are in the same group");
		RegisterClassVariableComment("LBGroupSettingsConfig", "groupManagePageObfuscatePlayernames", "enable / disable player Names being displayed in the Player list. If disabled the Names will be shown as usual. If enabled, the names will just be random numbers, which change every restart");
		RegisterClassVariableComment("LBGroupSettingsConfig", "enablePlayerList", "enable / disable the Player List in the top left corner");
		RegisterClassVariableComment("LBGroupSettingsConfig", "enablePlayerListDistance", "enable / disable if the Distance to the other Players should be displayed in the Player List");
		RegisterClassVariableComment("LBGroupSettingsConfig", "allowJoinSecondGroupTemporarily", "Enable secondary groups to not have to leave the main group to temporarily join another group");
		RegisterClassVariableComment("LBGroupSettingsConfig", "removeTemporaryMemberOnServerStart", "Enable if players should be removed from the temporary group on restart. Otherwise the player needs to leave the group or you enable `removeTemporaryMemberOnPlayerLeave`");
		RegisterClassVariableComment("LBGroupSettingsConfig", "removeTemporaryMemberOnPlayerLeave", "Enable if players should be removed from the temporary group when he leaves the server / logs out or server restart. Otherwise players need to actively leave the temporary group");
		RegisterClassVariableComment("LBGroupSettingsConfig", "enableSubGroups", "enable / disable subgroups / firegroups to split larger groups into smaller groups. This should make it harder for larger groups to run around as on big squad and wipe out every small group");
		RegisterClassVariableComment("LBGroupSettingsConfig", "enableSubGroupSharedPlayerMapMarker", "If enabled, the players can still see eachother even if not in the same subgroup, which makes the subgroups pointless");
		RegisterClassVariableComment("LBGroupSettingsConfig", "enableSubGroupSharedPingMapMarker", "Enable if the Ping Markers should be shared in the subgroups");
