		RegisterClassComment("LBSafezoneMarkers", "This file contains the config for Safezone Markers. They are only markers and do not add any safezone functionality.\n\nThis config also doesn't automatically take the safezones from other mods. They need to be marked by setting the `showAllPlayerNametags` for static markers to 1 or check the box ingame to make it a safezone marker.\n\nThe zones themselves are static markers with the `showAllPlayerNametags` parameter set to 1. They need a radius set too. The color of the radius can be invisible (circleColorA set to 0), if you don't want to show the circle on the map, but still want the nametags to be visible");
		RegisterClassVariableComment("LBSafezoneMarkers", "enablePlayerMarkers", "Enable / disable the whole feature");
		RegisterClassVariableComment("LBSafezoneMarkers", "showMarkersEverywhere", "Enable if markers should be visible everywhere on the whole map ignoring the zones of the static markers");
		RegisterClassVariableComment("LBSafezoneMarkers", "checkLineOfSight", "Check the line of sight from the player to the other players head");
		RegisterClassVariableComment("LBSafezoneMarkers", "obfuscatePlayerNames", "Show the obfuscated version of the Playernames instead of the real names. Will behave exactly the same like the obfuscation of player names on the online players list for the group invites. The IDs of the players will also be printed in the LBmaster log when they login so you can find out who the person was");
		RegisterClassVariableComment("LBSafezoneMarkers", "showOwnPlayerTag", "Enable if the tag of the own player should be displayed or hidden");
		RegisterClassVariableComment("LBSafezoneMarkers", "maxPlayerDistance", "Maximum distance the nametags will be shown. Cannot exceed the network far bubble (~1000m by default)");
		RegisterClassVariableComment("LBSafezoneMarkers", "safezoneMarkers", "List of all prefixes. You should always have one with no permissions, otherwise normal players will not have a prefix!");
		RegisterClassVariableComment("LBSafezoneMarkerEntry", "prefix", "Prefix infront of the playername. Will not be displayed when playername obfuscation is enabled");
		RegisterClassVariableComment("LBSafezoneMarkerEntry", "color", "Color of the tag");
		RegisterClassVariableComment("LBSafezoneMarkerEntry", "permission", "Permission required to have this prefix and color applied. Grant all permissions is ignored. Make sure to have exactly 1 entry with an empty permission");
		RegisterClassVariableComment("LBSafezoneMarkerEntry", "ignoreNameObfuscationSetting", "When enabled and playername obfuscation is enabled in the config, players with this tag will still have their plain name displayed");
		RegisterClassComment("LBStaticMarkerManager", "This config contains all static markers on the server. It is possible to add the static markers here, especially if you need a little more control over the markers, than you have with the ingame admin menu\n\nI still highly recomment using the ingame Admin menu to add static markers on your server. It's a lot easier for the initial setup.\n\nMake sure you are added to the Admins.json in your Config/Common/Admins.json file and have admin mode enabled. Then just place a marker on the map and change the type to Server Marker (perm) to add a static marker. You can define Name, Icon, Color and Radius ingame, which should be enough for everyone.\n\nMake sure if you do want to edit this file, to do that while the server is offline, otherwise changes are likely to be overwritten by the server.");
		RegisterClassVariableComment("LBServerMarker", "type", "Type of the Marker. 0 = Static Marker (persistent), 1 = Dynamic Marker (deleted after server restart), 2 = Ping Marker, 3 = Group Marker, 4 = Group Player Marker, 5 = Private Marker");
